import{_ as p}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as a,e as r}from"./app-a35d01d1.js";const h={},d=r('<h1 id="科目二" tabindex="-1"><a class="header-anchor" href="#科目二" aria-hidden="true">#</a> 科目二</h1><h2 id="直角转弯" tabindex="-1"><a class="header-anchor" href="#直角转弯" aria-hidden="true">#</a> 直角转弯</h2><p>对线行驶(雨刮器铆钉位置领右边行驶)</p><p>对线正确之后再开左转向灯</p><p>左门扣的尾端对角，向左打死方向盘</p><p>车正则回正</p><h2 id="曲线行驶" tabindex="-1"><a class="header-anchor" href="#曲线行驶" aria-hidden="true">#</a> 曲线行驶</h2><p>挡风玻璃下角对左线行驶</p><p>前车盖左突起部分刚压线向左打一圈微调</p><p>前车盖左突起部分又压线时回正方向</p><p>雨刮器铆钉位置压线向右打一圈微调</p><p>车正则回正方向</p><h2 id="侧方停车" tabindex="-1"><a class="header-anchor" href="#侧方停车" aria-hidden="true">#</a> 侧方停车</h2><p>对线行驶(雨刮器铆钉位置领右边行驶)前库角出现在右视镜中间停车</p><p>前库角在右视镜消失的瞬间向右打满方向</p><p>左视镜能看见库脚回正并且向左打180度</p><p>右轮压线向左打死(一圈)</p><p>车尾与线微窄停车(如果很宽则平行停车)</p><p>开左转向灯</p><p>前车盖左突起部分刚压线回正方向</p><p>雨刮器铆钉位置压线向右打一圈微调</p><p>车正则回正方向</p><h2 id="倒车入库" tabindex="-1"><a class="header-anchor" href="#倒车入库" aria-hidden="true">#</a> 倒车入库</h2><p>挡风玻璃下角对左线行驶</p><p>座椅座在线上停车</p><p>倒车至左后视镜下沿遮虚线右打满方向</p><p>看右视镜，当车尾离右库脚小于30公分距离时则回一圈如果很宽则不动</p><p>车尾与线微窄则回正方向，后退一定距离停车，观察左后视镜和右后视镜如果左边车离线很宽则下述步骤倒车时需要向左微调</p><p>出库当左黄线到达前窗后下角时左打一圈加90度方向保持不动压住线停车</p><p>倒车时看情况需不需要微调，当车尾离右库脚小于30公分距离时则回一圈如果很宽则打死方向</p><p>车尾与线平行则回正方向，后退一定距离停车</p>',31),t=[d];function i(n,c){return e(),a("div",null,t)}const _=p(h,[["render",i],["__file","科目二.html.vue"]]);export{_ as default};
